// Extract and validate the user query
const body = $input.first().json.body;
const query = body.query;
const department = body.department || null;
const userId = body.userId || 'anonymous';
const sessionId = body.sessionId || 'default';

if (!query || query.trim().length === 0) {
  throw new Error('Query is required');
}

// Clean and prepare the query
const cleanedQuery = query.trim();

// Set up context for the workflow
return {
  query: cleanedQuery,
  department: department,
  userId: userId,
  sessionId: sessionId,
  timestamp: new Date().toISOString(),
  requestId: `req_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`
};

// Prepare context and prompt for Claude
const queryData = $('Preprocess Query').first().json;
const searchResults = $input.first().json.results;

// Build context from search results
let context = '';
let sources = [];

if (searchResults && searchResults.length > 0) {
  context = searchResults.map((result, index) => {
    sources.push({
      title: result.title,
      source: result.source,
      department: result.department,
      score: result.score
    });

    return `[${index + 1}] ${result.title}\nSource: ${result.source}\nDepartment: ${result.department}\nContent: ${result.content}\n`;
  }).join('\n---\n\n');
} else {
  context = 'No relevant documents found in the knowledge base.';
}

// Construct the prompt for Claude
const prompt = `You are a helpful enterprise assistant with access to company documents. Answer the user's question based on the provided context.

## Context from Company Documents:
${context}

## User Question:
${queryData.query}

## Instructions:
- Answer based primarily on the provided context
- If the context doesn't contain enough information, clearly state this
- Provide specific references to source documents when possible
- Be concise but comprehensive
- Use a professional but friendly tone
- If no relevant context is found, provide a helpful general response and suggest contacting the appropriate department

## Answer:`;

return {
  prompt: prompt,
  query: queryData.query,
  context: context,
  sources: sources,
  requestId: queryData.requestId,
  userId: queryData.userId,
  sessionId: queryData.sessionId,
  department: queryData.department
};

// Format the final response
const promptData = $('Prepare Claude Prompt').first().json;
const claudeResponse = $input.first().json;

// Extract Claude's response
let answer = '';
if (claudeResponse.content && claudeResponse.content.length > 0) {
  answer = claudeResponse.content[0].text;
} else {
  answer = 'I apologize, but I was unable to generate a response. Please try again.';
}

// Prepare the final response
const response = {
  answer: answer,
  query: promptData.query,
  sources: promptData.sources,
  metadata: {
    requestId: promptData.requestId,
    userId: promptData.userId,
    sessionId: promptData.sessionId,
    department: promptData.department,
    timestamp: new Date().toISOString(),
    model: 'claude-sonnet-4-20250514',
    sourceCount: promptData.sources.length
  }
};

return response;

// Error handling
const error = $input.first().json.error || $input.first().json;

console.error('Workflow error:', error);

const errorResponse = {
  error: true,
  message: 'I apologize, but I encountered an error while processing your request. Please try again.',
  details: error.message || 'Unknown error',
  timestamp: new Date().toISOString()
};

return errorResponse;
